                TRL: ${row.cells[9]?.innerText || 'N/A'} | LOC: ${row.cells[5]?.innerText || 'N/A'}
            </div>
        `;
        containers[type].appendChild(div);
    }

    // --- UI BUILDER ---
    function initUI() {
        const bar = document.createElement('div');
        bar.id = 'departure-count-bar';
        const statuses = ['Scheduled', 'Progress', 'Finished', 'Paused', 'Cancelled', 'Twenty', 'HJB1', 'Container'];
        bar.innerHTML = statuses.map(s => `
            <div class="count-item">${s}: <span id="count-${s.toLowerCase()}" style="color:${CONFIG.colors[s.toLowerCase()] || '#fff'}">0</span></div>
        `).join('') + `<button id="refresh-counts">EXEC_RELOAD</button>`;
        document.body.prepend(bar);

        const panel = document.createElement('div');
        panel.id = 'time-alert-panel';
        panel.innerHTML = `
            <div id="alert-header"><span>TERMINAL_ALERTS</span><span id="alert-total">0</span></div>
            <div id="time-alert-content">
                <div id="urgent-alerts" style="margin-bottom:10px"><small style="color:${CONFIG.colors.urgentAlert}">[ CRITICAL ]</small><div class="container"></div></div>
                <div id="warning-alerts" style="margin-bottom:10px"><small style="color:${CONFIG.colors.warningAlert}">[ WARNING ]</small><div class="container"></div></div>
                <div id="upcoming-alerts"><small style="color:${CONFIG.colors.upcomingAlert}">[ INFO ]</small><div class="container"></div></div>
            </div>
        `;
        document.body.appendChild(panel);
    }

    // --- INIT ---
    function init() {
        applyStyles();
        initUI();

        // MutationObserver: Monitoring dynamic table changes
        const observer = new MutationObserver(() => updateAllData());
        const targetTable = document.querySelector('table.dataTable');
        if (targetTable) {
            observer.observe(targetTable, { childList: true, subtree: true });
        }

        updateAllData();
        setInterval(updateAllData, CONFIG.updateInterval);

        document.getElementById('refresh-counts').addEventListener('click', () => location.reload());
    }

    window.addEventListener('load', init);

})();
"}

