}

function calculate30m(base) {
    let [h, m] = base.split(':').map(Number);
    m += 30; if (m >= 60) { h = (h + 1) % 24; m -= 60; }
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
}

function update() {
    const rows = document.querySelectorAll("table.dataTable tbody tr");
    const now = new Date();
    const counts = { scheduled: 0, progress: 0, finished: 0, paused: 0, cancelled: 0, twenty: 0, hjb1: 0, container: 0 };
    const containers = {
        urgent: document.querySelector('#u-container'),
