        upcoming: document.querySelector('#s-container')
    };

    if (containers.urgent) Object.values(containers).forEach(c => c.innerHTML = '');

    rows.forEach(row => {
        const text = row.innerText;
        const status = row.cells[3]?.innerText.trim() || "";

        if (status.includes("Scheduled")) { counts.scheduled++; row.style.color = CONFIG.colors.scheduled; }
        else if (status.includes("Progress")) { counts.progress++; row.style.color = CONFIG.colors.progress; }
        else if (status.includes("Finished")) { counts.finished++; row.style.color = CONFIG.colors.finished; }

        if (text.toLowerCase().includes("twenty")) { counts.twenty++; row.style.color = CONFIG.colors.twenty; }

        const timeMatch = text.match(/\d{2}:\d{2}/);
        if (timeMatch && status !== "Finished") {
            const base = timeMatch[0], t30 = calculate30m(base);
            const [h, m] = t30.split(':').map(Number);
            const target = new Date(); target.setHours(h, m, 0, 0);
