    bar.innerHTML = ['Scheduled', 'Progress', 'Finished', 'Twenty'].map(s => `<div>${s}: <span id="cnt-${s.toLowerCase()}">0</span></div>`).join('') + `<button id="refresh-node">RELOAD</button>`;
    document.body.prepend(bar);

    const panel = document.createElement('div');
    panel.id = 'time-alert-panel';
    panel.innerHTML = `<div id="alert-header">Monitor_SSP</div><div id="time-alert-content">
        <div id="u-section"><small>[CRIT]</small><div id="u-container" class="container"></div></div>
        <div id="w-section"><small>[WARN]</small><div id="w-container" class="container"></div></div>
        <div id="s-section"><small>[STBY]</small><div id="s-container" class="container"></div></div>
    </div>`;
    document.body.appendChild(panel);

    const obs = new MutationObserver(() => update());
    const table = document.querySelector('table.dataTable');
    if (table) obs.observe(table, { childList: true, subtree: true });

    update();
    setInterval(update, CONFIG.updateInterval);
    document.getElementById('refresh-node').onclick = () => location.reload();
}

init();
