{"title":"js 1","content":"/* SSP Terminal System v6.0 - Expanded View & Draggable */
const CONFIG = {
    timeThresholds: { urgent: 15, warning: 30, upcoming: 60 },
    colors: {
        scheduled: '#808187', progress: '#CE9105', finished: '#03C314',
        paused: '#FF00E0', cancelled: '#FF0000', twenty: '#FF0000',
        hjb1: '#04DD20', container: '#DD04DC', urgentAlert: '#FF0000',
        warningAlert: '#FFA500', upcomingAlert: '#FFD700',
        panelBg: '#ffffff', textColor: '#212529', border: '#dee2e6', highlight: '#ff7300'
    }
};

function injectStyles() {
    const style = document.createElement('style');
    style.textContent = `
        :root { --mono: "JetBrains Mono", monospace; }

        #ssp-terminal {
            position: fixed; top: 120px; right: 20px;
            width: 350px; background: #fff;
            border: 2px solid #1a1a1a; border-radius: 0 !important;
            z-index: 10001; font-family: var(--mono);
            box-shadow: 10px 10px 0px rgba(0,0,0,0.15);
            transition: all 0.2s ease-in-out;

            &.maximized {
                width: 80vw; height: 70vh;
                top: 10vh !important; left: 10vw !important;
                & #terminal-list { grid-template-columns: repeat(3, 1fr); display: grid; gap: 15px; }
            }

            &.minimized {
                width: 45px; height: 45px; overflow: hidden;
                & #terminal-content, & #terminal-header span { display: none; }
            }
        }

        #terminal-header {
            background: #1a1a1a; color: #fff; padding: 10px;
            cursor: move; display: flex; justify-content: space-between;
            align-items: center; border-radius: 0;

            & .controls { display: flex; gap: 5px; }
            & button {
                background: #333; color: #fff; border: 1px solid #555;
                font-family: var(--mono); font-size: 10px; cursor: pointer;
                padding: 2px 6px; border-radius: 0;
                &:hover { background: ${CONFIG.colors.highlight}; }
            }
        }

        #terminal-content {
            padding: 15px; overflow-y: auto; max-height: calc(100% - 50px);
            background: ${CONFIG.colors.panelBg};
        }

        .data-card {
            border: 1px solid ${CONFIG.colors.border};
            padding: 10px; margin-bottom: 8px;
            border-left: 5px solid #ccc;
            border-radius: 0 !important;
            display: flex; flex-direction: column;

            & .card-top { display: flex; justify-content: space-between; font-weight: bold; }
            & .card-bot { font-size: 11px; margin-top: 5px; color: #666; }
        }

        .urgent-blink { animation: blinker 1s linear infinite; }
        @keyframes blinker { 50% { opacity: 0; } }
    `;
    document.head.appendChild(style);
}

function updateTerminal() {
    const rows = document.querySelectorAll("table.dataTable tbody tr");
    const list = document.querySelector("#terminal-list");
    if (!list) return;

    let content = "";
    rows.forEach(row => {
        const status = row.cells[3]?.innerText.trim();
        if (!status || status === "Finished") return;

        const timeStr = row.innerText.match(/\d{2}:\d{2}/);
        if (timeStr) {
            const [h, m] = timeStr[0].split(':').map(Number);
            const target = new Date();
            target.setHours(h, m + 30, 0, 0);
            const diff = Math.round((target - new Date()) / 60000);

            if (diff > -15 && diff < 180) {
                const color = diff <= CONFIG.timeThresholds.urgent ? CONFIG.colors.urgentAlert : 
                             (diff <= CONFIG.timeThresholds.warning ? CONFIG.colors.warningAlert : "#1a1a1a");

                content += `
                    <div class="data-card" style="border-left-color: ${color}">
                        <div class="card-top">
                            <span style="color: ${color}">${timeStr[0]} → ${diff}m</span>
                            <span>${status}</span>
                        </div>
                        <div class="card-bot">
                            TRL: ${row.cells[9]?.innerText || 'N/A'} | LOC: ${row.cells[5]?.innerText || 'N/A'}
                        </div>
                    </div>`;
            }
        }
    });
    list.innerHTML = content || "NO_ACTIVE_TASKS";
}

function dragElement(el) {
    let p1 = 0, p2 = 0, p3 = 0, p4 = 0;
    el.querySelector("#terminal-header").onmousedown = (e) => {
        if (el.classList.contains('maximized')) return;
        e.preventDefault();
        p3 = e.clientX; p4 = e.clientY;
        document.onmouseup = () => { document.onmouseup = null; document.onmousemove = null; };
        document.onmousemove = (e) => {
            e.preventDefault();
            p1 = p3 - e.clientX; p2 = p4 - e.clientY;
            p3 = e.clientX; p4 = e.clientY;
            el.style.top = (el.offsetTop - p2) + "px";
            el.style.left = (el.offsetLeft - p1) + "px";
            el.style.right = "auto";
        };
    };
}

function init() {
    injectStyles();
    const term = document.createElement('div');
    term.id = 'ssp-terminal';
    term.innerHTML = `
        <div id="terminal-header">
            <span>TERMINAL_V6</span>
            <div class="controls">
                <button id="btn-refresh">REF</button>
                <button id="btn-size">MAX</button>
                <button id="btn-min">_</button>
            </div>
        </div>
        <div id="terminal-content">
            <div id="terminal-list"></div>
        </div>
    `;
    document.body.appendChild(term);

    dragElement(term);

    const btnSize = document.getElementById("btn-size");
    const btnMin = document.getElementById("btn-min");

    btnSize.onclick = () => {
        term.classList.toggle("maximized");
        term.classList.remove("minimized");
        btnSize.innerText = term.classList.contains("maximized") ? "SMALL" : "MAX";
    };

    btnMin.onclick = () => {
        term.classList.toggle("minimized");
        term.classList.remove("maximized");
    };

    document.getElementById("btn-refresh").onclick = updateTerminal;

    const observer = new MutationObserver(updateTerminal);
    const table = document.querySelector('table.dataTable');
    if (table) observer.observe(table, { childList: true, subtree: true });

    updateTerminal();
}

init();
"}
